4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; cursed?: boolean; enchantment?: number };
24	type QuoteStep = { op: "quote"; items: Array<Item> };
25	type Customer = { yearsWithMHPCO: number };
26	type Scenario = { customer: Customer; steps: Array<QuoteStep> };
27	
28	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
29	
30	const countByType = (items: Item[]): Record<string, number> => {
31	  const counts: Record<string, number> = {};
32	  for (const item of items) {
33	    counts[item.type] = (counts[item.type] ?? 0) + 1;
34	  }
35	  return counts;
36	};
37	
38	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
39	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
40	
41	const subtotalForType = (type: string, count: number): number =>
42	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
43	
44	const policyBaseFor = (items: Item[]): number =>
45	  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));
46	
47	const isHighlyEnchanted = (item: Item): boolean =>
48	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
49	
50	const surchargeRate = (item: Item): number =>
51	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
52	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
53	
54	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
55	
56	const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));
57	
58	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
59	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
60	
61	const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
62	  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
63	
64	const firstInsuranceSurchargeFor = (policyBase: number): number =>
65	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
66	
67	const isFollowUpQuote = (quoteIndex: number): boolean => quoteIndex > 0;
68	
69	const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
70	  isFollowUpQuote(quoteIndex) ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
71	
72	const quotePremium = (step: QuoteStep, customer: Customer, quoteIndex: number): number => {
73	  const policyBase = policyBaseFor(step.items);
74	  const itemSurchargesTotal = itemSurchargesFor(step.items);
75	  const firstInsuranceSurcharge = firstInsuranceSurchargeFor(policyBase);
76	  const loyaltyDiscount = loyaltyDiscountFor(policyBase, customer);
77	  const followUpDiscount = followUpDiscountFor(policyBase, quoteIndex);
78	  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
79	};
80	
81	export const runScenario = (input: unknown): unknown => {
82	  const scenario = input as Scenario;
83	  const results = scenario.steps.map((step, quoteIndex) => ({
84	    premium: quotePremium(step, scenario.customer, quoteIndex),
85	  }));
86	  return { results };
87	};
